const phase = body.phase || 1;
const intensity = body.intensity || 'low';

if (phase < 1 || phase > 6) throw new Error('Invalid phase: ' + phase);

const descriptions = {
  1: 'Normal Operations',
  2: 'Atmosphere Building - Rumors begin',
  3: 'Rumor Spread - Fear campaign',
  4: 'Escalation - Hack reports, GORGON threats',
  5: 'Manipulation - Fake statements, insider leaks',
  6: 'Total Offensive - All channels mobilized'
};

const intervals = { low: 300, medium: 120, high: 60, max: 15 };

return [{ json: { phase, intensity, description: descriptions[phase], postInterval: intervals[intensity] || 60 } }];

const phaseInfo = $('Parse Input').first().json;
const phase = phaseInfo.phase;
const intensity = phaseInfo.intensity;
const allNpcs = $('Get NPC List').all().flatMap(item => Array.isArray(item.json) ? item.json : [item.json]);

// Helper: find NPCs by country/role
const findNpcs = (country, role) => allNpcs.filter(n => {
  const attrs = n.npcProfile?.attributes || n.attributes || {};
  return attrs.country === country && attrs.role === role;
});

// Helper: derive username
const deriveUsername = (npc) => {
  const first = npc.npcProfile?.name?.first || npc.name?.first || '';
  const last = npc.npcProfile?.name?.last || npc.name?.last || '';
  if (!first || !last) return null;
  return (first[0] + last).toLowerCase().replace(/[^a-z0-9_]/g, '');
};

